export function PlatformIcon({ platform, size = 14 }: { platform: string; size?: number }) {
  const icon = ICONS[platform];
  if (!icon) {
    return (
      <span
        className="rounded-full bg-white/20 shrink-0 inline-block"
        style={{ width: size, height: size }}
      />
    );
  }
  return (
    <svg
      viewBox="0 0 24 24"
      fill={icon.color}
      width={size}
      height={size}
      className="shrink-0"
      aria-label={platform}
    >
      <path d={icon.path} />
    </svg>
  );
}
